-- INDEXES FOR PERFORMANCE OPTIMIZATION
-- =============================================================================

-- Games indexes
CREATE INDEX IF NOT EXISTS idx_games_game_id ON games(game_id);
CREATE INDEX IF NOT EXISTS idx_games_team_id ON games(team_id);
