-- 2. TEAMS TABLE CONSTRAINTS
-- =============================================================================

-- Add unique constraint on team name (active teams only)
CREATE UNIQUE INDEX IF NOT EXISTS idx_teams_name_unique 
ON teams(LOWER(TRIM(name))) 
WHERE deleted_at IS NULL;

