DROP TRIGGER IF EXISTS trigger_create_default_channels ON public.teams;
CREATE TRIGGER trigger_create_default_channels
    AFTER INSERT ON public.teams
    FOR EACH ROW
    EXECUTE FUNCTION create_default_team_channels();

