);

-- Insert staff roles
INSERT INTO staff_roles (id, display_name, category, can_manage_roster, can_delete_players, can_view_health_data, sort_order) VALUES
    -- Ownership
    ('owner', 'Team Owner', 'ownership', true, true, true, 1),
