-- Verify psychologist role was added
DO $$
DECLARE
    v_count INTEGER;
BEGIN
    SELECT COUNT(*) INTO v_count
    FROM staff_roles
    WHERE id = 'psychologist';
    
    IF v_count = 0 THEN
