    'game_day_recovery',
    'travel_recovery',
    'injury_recovery',
    'wellness_recovery'
  )),
  start_date DATE NOT NULL,
  end_date DATE NOT NULL,
  max_load_percent INTEGER CHECK (max_load_percent BETWEEN 0 AND 100),
