FROM pg_indexes
WHERE schemaname = 'public'
  AND indexname IN (
    'idx_training_sessions_status_date',
    'idx_training_sessions_user_status_date',
    'idx_load_monitoring_player_date',
    'idx_training_analytics_user_type_date',
